"use client";

/**
 * DetailPanel Component
 *
 * A slide-over panel for viewing and editing entity details.
 * Optimized for Product Mode with focused interactions.
 *
 * @example
 * ```tsx
 * <DetailPanel
 *   open={isOpen}
 *   onClose={() => setIsOpen(false)}
 *   title="User Details"
 *   description="Edit user profile information"
 *   footer={<Button>Save Changes</Button>}
 * >
 *   <UserForm />
 * </DetailPanel>
 * ```
 */

import { forwardRef, useEffect, useRef } from "react";
import { X } from "lucide-react";
import type { DetailPanelProps } from "./DetailPanel.types";
import styles from "./DetailPanel.module.css";

export const DetailPanel = forwardRef<HTMLDivElement, DetailPanelProps>(
  (
    {
      open,
      onClose,
      title,
      description,
      subtitle,
      children,
      size = "md",
      position = "right",
      headerActions,
      footer,
      overlay = true,
      closeOnOverlayClick = true,
      closeOnEscape = true,
      loading = false,
      className,
      ...rest
    },
    ref,
  ) => {
    const panelRef = useRef<HTMLDivElement>(null);

    // Support deprecated subtitle prop with warning
    const effectiveDescription = description ?? subtitle;

    // Deprecation warning
    useEffect(() => {
      if (subtitle && process.env.NODE_ENV === "development") {
        console.warn(
          '[DetailPanel] The "subtitle" prop is deprecated. Use "description" instead. ' +
            "subtitle will be removed in v3.0.",
        );
      }
    }, [subtitle]);

    // Handle Escape key
    useEffect(() => {
      if (!open || !closeOnEscape) return;

      const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === "Escape") {
          onClose();
        }
      };

      document.addEventListener("keydown", handleKeyDown);
      return () => document.removeEventListener("keydown", handleKeyDown);
    }, [open, closeOnEscape, onClose]);

    // Trap focus and prevent body scroll
    useEffect(() => {
      if (open) {
        const originalOverflow = document.body.style.overflow;
        document.body.style.overflow = "hidden";

        // Focus the panel
        setTimeout(() => {
          panelRef.current?.focus();
        }, 0);

        return () => {
          document.body.style.overflow = originalOverflow;
        };
      }
    }, [open]);

    if (!open) return null;

    const handleOverlayClick = () => {
      if (closeOnOverlayClick) {
        onClose();
      }
    };

    const classNames = [
      styles.panel,
      styles[`size-${size}`],
      styles[`position-${position}`],
      className,
    ]
      .filter(Boolean)
      .join(" ");

    return (
      <div className={styles.container}>
        {/* Overlay */}
        {overlay && (
          <div
            className={styles.overlay}
            onClick={handleOverlayClick}
            aria-hidden="true"
          />
        )}

        {/* Panel */}
        <div
          ref={ref || panelRef}
          className={classNames}
          role="dialog"
          aria-modal="true"
          aria-labelledby="detail-panel-title"
          tabIndex={-1}
          {...rest}
        >
          {/* Header */}
          <div className={styles.header}>
            <div className={styles.headerContent}>
              <h2 id="detail-panel-title" className={styles.title}>
                {title}
              </h2>
              {effectiveDescription && (
                <p className={styles.subtitle}>{effectiveDescription}</p>
              )}
            </div>
            <div className={styles.headerActions}>
              {headerActions}
              <button
                type="button"
                className={styles.closeButton}
                onClick={onClose}
                aria-label="Close panel"
              >
                <X size={20} />
              </button>
            </div>
          </div>

          {/* Body */}
          <div className={styles.body}>
            {loading ? (
              <div className={styles.loading}>
                <div className={styles.spinner} />
              </div>
            ) : (
              children
            )}
          </div>

          {/* Footer */}
          {footer && <div className={styles.footer}>{footer}</div>}
        </div>
      </div>
    );
  },
);

DetailPanel.displayName = "DetailPanel";

/**
 * DetailPanel Component Types
 *
 * Type definitions for the Orion DetailPanel section component.
 * A slide-over panel for viewing and editing entity details.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * DetailPanel size
 */
export type DetailPanelSize = "sm" | "md" | "lg" | "xl";

/**
 * DetailPanel position
 */
export type DetailPanelPosition = "right" | "left";

/**
 * DetailPanel section props
 *
 * @example
 * ```tsx
 * <DetailPanel
 *   open={isOpen}
 *   onClose={() => setIsOpen(false)}
 *   title="User Details"
 *   description="Edit user profile information"
 *   footer={<Button>Save</Button>}
 * >
 *   <UserForm />
 * </DetailPanel>
 * ```
 */
export interface DetailPanelProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "title"
> {
  /**
   * Whether the panel is open
   */
  open: boolean;

  /**
   * Close callback
   */
  onClose: () => void;

  /**
   * Panel title
   */
  title: ReactNode;

  /**
   * Optional description text below title
   */
  description?: ReactNode;

  /**
   * @deprecated Use `description` instead. Will be removed in v3.0.
   */
  subtitle?: ReactNode;

  /**
   * Panel content
   */
  children: ReactNode;

  /**
   * Panel size
   * - sm: 320px
   * - md: 480px
   * - lg: 640px
   * - xl: 800px
   * @default 'md'
   */
  size?: DetailPanelSize;

  /**
   * Panel position
   * @default 'right'
   */
  position?: DetailPanelPosition;

  /**
   * Header actions (buttons in header area)
   */
  headerActions?: ReactNode;

  /**
   * Footer content
   */
  footer?: ReactNode;

  /**
   * Show overlay backdrop
   * @default true
   */
  overlay?: boolean;

  /**
   * Close on overlay click
   * @default true
   */
  closeOnOverlayClick?: boolean;

  /**
   * Close on Escape key
   * @default true
   */
  closeOnEscape?: boolean;

  /**
   * Loading state
   * @default false
   */
  loading?: boolean;
}

/**
 * DetailPanel Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Slide-over panel for focused detail views.
 */

.container {
  position: fixed;
  inset: 0;
  z-index: var(--z-modal);
  display: flex;
}

/* ============================================================================
 * OVERLAY
 * ============================================================================ */

.overlay {
  position: absolute;
  inset: 0;
  background: var(--surface-overlay);
  animation: fadeIn 200ms ease-out;
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

/* ============================================================================
 * PANEL
 * ============================================================================ */

.panel {
  position: absolute;
  top: 0;
  bottom: 0;
  display: flex;
  flex-direction: column;
  background: var(--surface-base);
  box-shadow: var(--shadow-xl);
  outline: none;
}

.position-right {
  right: 0;
  border-left: 1px solid var(--border-subtle);
  animation: slideInRight 200ms ease-out;
}

.position-left {
  left: 0;
  border-right: 1px solid var(--border-subtle);
  animation: slideInLeft 200ms ease-out;
}

@keyframes slideInRight {
  from {
    transform: translateX(100%);
  }
  to {
    transform: translateX(0);
  }
}

@keyframes slideInLeft {
  from {
    transform: translateX(-100%);
  }
  to {
    transform: translateX(0);
  }
}

/* Sizes */
.size-sm {
  width: 320px;
}

.size-md {
  width: 480px;
}

.size-lg {
  width: 640px;
}

.size-xl {
  width: 800px;
}

/* ============================================================================
 * HEADER
 * ============================================================================ */

.header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--spacing-4);
  padding: var(--spacing-4) var(--spacing-6);
  border-bottom: 1px solid var(--border-subtle);
  flex-shrink: 0;
}

.headerContent {
  flex: 1;
  min-width: 0;
}

.title {
  font-family: var(--font-secondary);
  font-size: var(--font-size-18);
  font-weight: var(--font-weight-semibold);
  color: var(--text-primary);
  margin: 0;
  line-height: var(--line-height-tight);
}

.subtitle {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-secondary);
  margin: var(--spacing-1) 0 0 0;
  line-height: var(--line-height-relaxed);
}

.headerActions {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  flex-shrink: 0;
}

.closeButton {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  background: none;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  color: var(--text-secondary);
  transition:
    background-color var(--mode-hover-duration),
    color var(--mode-hover-duration);
}

.closeButton:hover {
  background: var(--surface-subtle);
  color: var(--text-primary);
}

.closeButton:focus-visible {
  outline: 2px solid var(--interactive-primary);
  outline-offset: 2px;
}

/* ============================================================================
 * BODY
 * ============================================================================ */

.body {
  flex: 1;
  overflow-y: auto;
  padding: var(--spacing-6);
}

/* ============================================================================
 * FOOTER
 * ============================================================================ */

.footer {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: var(--spacing-3);
  padding: var(--spacing-4) var(--spacing-6);
  border-top: 1px solid var(--border-subtle);
  background: var(--surface-subtle);
  flex-shrink: 0;
}

/* ============================================================================
 * LOADING
 * ============================================================================ */

.loading {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 200px;
}

.spinner {
  width: 32px;
  height: 32px;
  border: 3px solid var(--surface-subtle);
  border-top-color: var(--interactive-primary);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 640px) {
  .panel {
    width: 100% !important;
    max-width: 100%;
  }

  .header,
  .body,
  .footer {
    padding-left: var(--spacing-4);
    padding-right: var(--spacing-4);
  }
}

export { DetailPanel } from "./DetailPanel";
export type {
  DetailPanelProps,
  DetailPanelSize,
  DetailPanelPosition,
} from "./DetailPanel.types";
